function ls(k,d){
  var mc=window._MC&&window._MC[k];
  if(mc!==undefined&&mc!==null)return mc;
  try{var v=localStorage.getItem(k);return v?JSON.parse(v):d;}catch(e){return d;}
}
function lss(k,v){
  try{localStorage.setItem(k,JSON.stringify(v));}catch(e){}
  if(window._fsSave)window._fsSave(k,v);
}
var DEFAULT_LOGO='data:image/png;base64,';
function getU(){return ls(DB.USERS,SEED_USERS);}
function setU(v){lss(DB.USERS,v);}
function getLogo(){return ls('app_logo',null);}
function setLogo(v){lss('app_logo',v);}
function applyLogo(){
  var logo=getLogo()||DEFAULT_LOGO;
  document.querySelectorAll('.app-logo').forEach(function(img){img.src=logo;});
}
