function nid(arr){return arr.length?Math.max.apply(null,arr.map(function(x){return x.id;}))+1:1;}
function td(){return new Date().toISOString().slice(0,10);}
function fd(d){if(!d)return'';var dt=new Date(d+'T00:00:00');return dt.toLocaleDateString('en-IN',{day:'2-digit',month:'short',year:'numeric'});}
function mn(m){return['Jan','Feb','Mar','Apr','May','Jun','Jul','Aug','Sep','Oct','Nov','Dec'][m-1];}
function ru(n){return String.fromCharCode(8377)+Number(n).toLocaleString('en-IN',{minimumFractionDigits:2,maximumFractionDigits:2});}
function ago(iso){var d=Date.now()-new Date(iso).getTime(),m=Math.floor(d/60000);if(m<1)return'just now';if(m<60)return m+'m ago';var h=Math.floor(m/60);if(h<24)return h+'h ago';return Math.floor(h/24)+'d ago';}

// ============ STATE ============
var CU=null; // current user
var CP='/dashboard';   // current path - init to dashboard
var calM={y:new Date().getFullYear(),m:new Date().getMonth()+1};

// ============ INIT ============
async function init(){
  // Show loading overlay while Firestore loads and the app renders
  document.getElementById('app').style.display='none';
  var ov=document.getElementById('fsLoadOverlay');
  if(ov)ov.style.display='flex';
  try{ if(window._fsLoad) await window._fsLoad(); }catch(e){}

  if(!ls(DB.USERS,null)) lss(DB.USERS,SEED_USERS);
  if(!ls(DB.HOL,null))   lss(DB.HOL,SEED_HOL);
  applyLogo();
  applyCompanyName();
  var saved=sessionStorage.getItem('hr_sess');
  if(saved){try{CU=JSON.parse(saved);}catch(e){CU=null;}}
  if(CU){
    launchApp();
  } else {
    showLoginPage();
  }
  if(ov)ov.style.display='none';
}
function showLoginPage(){
  document.getElementById('app').style.display='none';
  document.getElementById('loginPage').style.display='flex';
}
function doLoginSubmit(){
  var u=document.getElementById('li_u').value.trim();
  var p=document.getElementById('li_p').value;
  var err=document.getElementById('li_err');
  var users=getU();
  var found=users.filter(function(x){return x.username===u&&x.password===p&&x.isActive;})[0];
  if(!found){err.style.display='block';err.textContent='Invalid username or password.';return;}
  CU=found;
  sessionStorage.setItem('hr_sess',JSON.stringify(CU));
  document.getElementById('loginPage').style.display='none';
  launchApp();
}
function launchApp(){
  document.getElementById('app').style.display='';
  document.getElementById('loginPage').style.display='none';
  renderSidebar();
  renderSwitchMenus();
  updateNBadge();
  var isEmp=CU.role==='employee';
  document.getElementById('botNav').style.display=isEmp?'flex':'none';
  document.getElementById('adminBotNav').style.display=(!isEmp)?'flex':'none';
  var target=CU.role==='admin'?'/admin/dash':'/dashboard';
  go(target);
  // Re-render after short delay to ensure DOM is settled (fixes blank-on-first-load)
  setTimeout(function(){ if(CP===target) go(target); }, 150);
  scheduleDailyNotif();
}

function doLogout(){
  CU=null;
  sessionStorage.removeItem('hr_sess');
  document.getElementById('app').style.display='none';
  document.getElementById('adminBotNav').style.display='none';
  document.getElementById('botNav').style.display='none';
  document.getElementById('loginPage').style.display='flex';
  document.getElementById('li_u').value='';
  document.getElementById('li_p').value='';
  document.getElementById('li_err').style.display='none';
}

function switchTo(uid){
  var u=getU().filter(function(x){return x.id===uid&&x.isActive;})[0];
  if(!u)return;
  CU=u;
  sessionStorage.setItem('hr_sess',JSON.stringify(u));
  closeAll();
  renderSidebar();
  renderSwitchMenus();
  updateNBadge();
  document.getElementById('botNav').style.display=u.role==='employee'?'flex':'none';document.getElementById('adminBotNav').style.display=u.role==='admin'?'flex':'none';
  go(u.role==='admin'?'/admin/dash':'/dashboard');
  toast('Switched to '+u.name);
}

