function go(path){
  CP=path;
  renderSidebar();
  updateBotNav();
  var fn=ROUTES[path];
  var el=document.getElementById('page');
  el.innerHTML=fn?fn():'<div class="card"><p style="color:#94a3b8">Page not found.</p></div>';
  if(path==='/dashboard'&&CU.role==='employee'){
    calM={y:new Date().getFullYear(),m:new Date().getMonth()+1};
    renderCal();
  }
  window.scrollTo(0,0);
}
function updateBotNav(){
  var mp={'/dashboard':'bn0','/att/history':'bn1','/att/submit':'bn2','/leave/apply':'bn3','/profile':'bn4'};
  ['bn0','bn1','bn2','bn3','bn4'].forEach(function(id){
    var el=document.getElementById(id);
    if(el)el.classList.toggle('active',mp[CP]===id);
  });
  var amp={'/admin/dash':'abn0','/admin/att':'abn1','/admin/staff':'abn2','/admin/salary':'abn3'};
  ['abn0','abn1','abn2','abn3','abn4'].forEach(function(id){
    var el=document.getElementById(id);
    if(el)el.classList.toggle('active',amp[CP]===id);
  });
}

// ============ HELPERS ============
function badge(s,t){
  var cls={present:'bg-green',absent:'bg-red',half_day:'bg-yellow',sunday_work:'bg-teal',holiday_work:'bg-purple',leave:'bg-blue',pending:'bg-orange',approved:'bg-green',rejected:'bg-red',casual:'bg-blue',sick:'bg-red',comp_off:'bg-teal',personal:'bg-orange',not_submitted:'bg-red',active:'bg-green',inactive:'bg-red',paid:'bg-green',cash_voucher:'bg-blue',project_expense:'bg-teal',travel_expense:'bg-purple'};
  var lbl={present:'Present',absent:'Absent',half_day:'Half Day',sunday_work:'Sunday Work',holiday_work:'Holiday Work',leave:'On Leave',pending:'Pending',approved:'Approved',rejected:'Rejected',casual:'Casual Leave',sick:'Sick Leave',comp_off:'Comp Off',personal:'Personal (LOP)',not_submitted:'No Record',active:'Active',inactive:'Inactive',paid:'Paid',cash_voucher:'Cash Voucher',project_expense:'Project Expense',travel_expense:'Travel Expense'};
  var k=s||'';
  return '<span class="badge '+(cls[k]||'bg-gray')+'">'+(t||lbl[k]||k)+'</span>';
}
function calcSal(uid,month,year){
  var att=getA().filter(function(a){return a.userId===uid&&a.status==='approved';});
  var hols=getH();
  var paid=0;
  att.forEach(function(a){
    var d=new Date(a.date+'T00:00:00');
    if(d.getFullYear()!==year||d.getMonth()+1!==month)return;
    if(a.type==='present'||a.type==='sunday_work'||a.type==='holiday_work')paid+=1;
    else if(a.type==='half_day')paid+=0.5;
    else if(a.type==='leave')paid+=1;
  });
  hols.forEach(function(h){
    var d=new Date(h.date+'T00:00:00');
    if(d.getFullYear()===year&&d.getMonth()+1===month)paid+=1;
  });
  var user=getU().filter(function(u){return u.id===uid;})[0];
  var mo=user?Number(user.monthlySalary):0;
  var wd=26;
  var gross=Math.min(mo,mo/wd*paid);
  return{paid:Math.min(paid,wd),wd:wd,gross:gross,ded:Math.max(0,mo-gross),net:gross,mo:mo};
}
function leaveBal(uid){
  var leaves=getL().filter(function(l){return l.userId===uid&&l.status==='approved';});
  var cu=0,su=0,co=0,pu=0;
  leaves.forEach(function(l){
    var d=Math.round((new Date(l.endDate)-new Date(l.startDate))/86400000)+1;
    if(l.type==='casual')cu+=d;
    else if(l.type==='sick')su+=d;
    else if(l.type==='comp_off')co+=d;
    else if(l.type==='personal')pu+=d;
  });
  var earned=getA().filter(function(a){return a.userId===uid&&a.status==='approved'&&(a.type==='sunday_work'||a.type==='holiday_work');}).length;
  return{casUsed:cu,casLeft:Math.max(0,12-cu),sikUsed:su,compEarned:earned,compLeft:Math.max(0,earned-co),personalUsed:pu};
}

// ============ CALENDAR ============
function renderCal(){
  var el=document.getElementById('calGrid');
  if(!el)return;
  var y=calM.y,m=calM.m;
  var titleEl=document.getElementById('calTitle');
  if(titleEl)titleEl.textContent=mn(m)+' '+y;
  var hols=getH();var att=getA().filter(function(a){return a.userId===CU.id;});
  var aMap={};att.forEach(function(a){aMap[a.date]=a;});
  var hMap={};hols.forEach(function(h){hMap[h.date]=h.name;});
  var todayStr=td();
  var first=new Date(y,m-1,1);
  var lastD=new Date(y,m,0).getDate();
  var startDow=first.getDay();
  var html='';
  for(var i=0;i<startDow;i++)html+='<div></div>';
  for(var d=1;d<=lastD;d++){
    var ds=y+'-'+pad(m)+'-'+pad(d);
    var isSun=new Date(ds+'T00:00:00').getDay()===0;
    var isHol=!!hMap[ds];
    var rec=aMap[ds];
    var isPast=ds<todayStr;
    var isToday=ds===todayStr;
    var isFuture=ds>todayStr;
    var cls='cal-day';
    var extra='';
    if(isToday)cls+=' cal-today';
    var canClick=false;
    var clickable='';
    if(rec){
      if(rec.status==='pending')cls+=' cal-pending';
      else if(rec.status==='rejected')cls+=' cal-miss';
      else{
        var tc={present:'cal-present',half_day:'cal-half',absent:'cal-absent',sunday_work:'cal-swork',holiday_work:'cal-hwork',leave:'cal-leave'};
        cls+=' '+(tc[rec.type]||'cal-present');
      }
      canClick=true;
    } else if(isFuture){
      if(isSun)cls+=' cal-sun';
      else if(isHol)cls+=' cal-holiday';
      else cls+=' cal-future';
    } else if(isToday){
      if(isSun){cls+=' cal-sun';canClick=true;}
      else if(isHol){cls+=' cal-holiday';canClick=true;}
      else{cls+=' cal-today-log';canClick=true;}
    } else {
      if(isSun){cls+=' cal-sun';canClick=true;}
      else if(isHol){cls+=' cal-holiday';canClick=true;}
      else{cls+=' cal-miss';canClick=true;}
    }
    if(canClick)clickable=' onclick="openDay(\''+ds+'\')"';
    html+='<div class="'+cls+'"'+clickable+' title="'+d+(isHol?' - '+hMap[ds]:'')+'"><span>'+d+'</span>'+(isSun&&!rec?'<span style="font-size:8px;opacity:.6">off</span>':'')+'</div>';
  }
  el.innerHTML=html;
}
function pad(n){return n<10?'0'+n:String(n);}
function calPrev(){calM.m--;if(calM.m<1){calM.m=12;calM.y--;}renderCal();}
function calNext(){calM.m++;if(calM.m>12){calM.m=1;calM.y++;}renderCal();}

