function dayTab(t){
  document.getElementById('dta').style.display=t==='a'?'':'none';
  document.getElementById('dtl').style.display=t==='l'?'':'none';
  document.getElementById('dt_a').style.cssText='flex:1;padding:8px;border:none;font-size:12px;font-weight:600;cursor:pointer;background:'+(t==='a'?'#0f766e':'#fff')+';color:'+(t==='a'?'#fff':'#64748b');
  document.getElementById('dt_l').style.cssText='flex:1;padding:8px;border:none;font-size:12px;font-weight:600;cursor:pointer;background:'+(t==='l'?'#0f766e':'#fff')+';color:'+(t==='l'?'#fff':'#64748b');
}
function submitDayAtt(ds){
  var type=document.getElementById('day_type').value;
  var note=document.getElementById('day_note').value.trim();
  var tin=document.getElementById('day_tin')?document.getElementById('day_tin').value:'09:00';
  var tout=document.getElementById('day_tout')?document.getElementById('day_tout').value:'18:00';
  if(!tin||!tout){toast('Time required','err');return;}
  var att=getA();
  var existingCalIdx=att.findIndex(function(a){return a.userId===CU.id&&a.date===ds;});
  if(existingCalIdx>=0){
    if(att[existingCalIdx].status!=='rejected'){toast('Already submitted for this date','err');return;}
    att[existingCalIdx]={id:att[existingCalIdx].id,userId:CU.id,date:ds,type:type,timeIn:tin,timeOut:tout,notes:note,status:'pending',createdAt:new Date().toISOString()};
  } else {
    att.push({id:nid(att),userId:CU.id,date:ds,type:type,timeIn:tin,timeOut:tout,notes:note,status:'pending',createdAt:new Date().toISOString()});
  }
  setA(att);closeModal();renderCal();toast('Attendance submitted!');
  if(CP==='/dashboard')go('/dashboard');
}
function submitDayLeave(ds){
  var ltype=document.getElementById('day_ltype').value;
  var lto=document.getElementById('day_lto').value;
  var reason=document.getElementById('day_lreason').value.trim();
  if(!reason){toast('Reason required','err');return;}
  if(lto<ds){toast('End date must be on or after start','err');return;}
  var leaves=getL();
  var days=Math.round((new Date(lto)-new Date(ds))/86400000)+1;
  leaves.push({id:nid(leaves),userId:CU.id,type:ltype,startDate:ds,endDate:lto,days:days,reason:reason,status:'pending',createdAt:new Date().toISOString()});
  setL(leaves);closeModal();toast('Leave applied!');
  if(CP==='/dashboard')go('/dashboard');
}

