        +'<td><code style="background:#f1f5f9;padding:2px 6px;border-radius:4px;font-size:11px">'+u.username+'</code></td>'
        +'<td>'+(u.department||'&mdash;')+'</td><td>'+(u.designation||'&mdash;')+'</td>'
