    +'<div style="display:grid;grid-template-columns:1fr 1fr;gap:10px;margin-bottom:10px"><div><label class="label">From</label><input class="input" type="date" id="lf" onchange="updDays()"/></div><div><label class="label">To</label><input class="input" type="date" id="le" onchange="updDays()"/></div></div>'
    +'<div id="ldur" style="display:none;padding:8px;background:#f1f5f9;border-radius:8px;text-align:center;font-size:12px;font-weight:600;margin-bottom:10px"></div>'
    +'<div style="margin-bottom:14px"><label class="label">Reason</label><textarea class="input" id="lr" rows="3" placeholder="Reason..."></textarea></div>'
    +'<button class="btn btn-p" onclick="submitLeave()" style="width:100%;justify-content:center">Submit Leave Request</button>'
