function updDays(){
  var s=document.getElementById('lf');var e=document.getElementById('le');var d=document.getElementById('ldur');
  if(!s||!e||!d)return;
  if(s.value&&e.value&&e.value>=s.value){var days=Math.round((new Date(e.value)-new Date(s.value))/86400000)+1;d.style.display='block';d.textContent='Duration: '+days+' day'+(days!==1?'s':'');}
}
function submitLeave(){
  var type=document.getElementById('lt').value;
  var start=document.getElementById('lf').value;var end=document.getElementById('le').value;
  var reason=document.getElementById('lr').value.trim();
  if(!start||!end||!reason){toast('All fields required','err');return;}
  if(start>end){toast('End must be after start','err');return;}
  var leaves=getL();
  var days=Math.round((new Date(end)-new Date(start))/86400000)+1;
  leaves.push({id:nid(leaves),userId:CU.id,type:type,startDate:start,endDate:end,days:days,reason:reason,status:'pending',createdAt:new Date().toISOString()});
  setL(leaves);go('/leave/history');toast('Leave request submitted!');
}

