function pgPurchase(){
  var invs=getPI().filter(function(p){return p.userId===CU.id;}).sort(function(a,b){return b.createdAt.localeCompare(a.createdAt);});
  return '<div><div style="margin-bottom:18px"><h1 style="font-size:22px;font-weight:700">Purchase Invoice</h1><p style="color:#64748b;font-size:13px">Upload a purchase invoice and the project it relates to.</p></div>'
    +'<div class="card" style="margin-bottom:16px">'
    +'<h3 style="font-weight:600;margin-bottom:14px;font-size:14px">Upload New Invoice</h3>'
    +'<div style="margin-bottom:10px"><label class="label">Invoice File</label>'
    +'<div id="invPreviewBox" style="margin-top:4px;padding:14px;border:1px dashed #d1d5db;border-radius:10px;background:#f8fafc;display:flex;align-items:center;justify-content:center;min-height:64px"><span style="color:#94a3b8;font-size:12px">No file selected</span></div>'
    +'<input type="file" id="invFileInput" accept="image/png,image/jpeg,image/jpg,image/webp,application/pdf" class="input" style="padding:8px;margin-top:8px" onchange="onInvoiceFileChosen(event)">'
    +'<div style="font-size:11px;color:#94a3b8;margin-top:6px">PNG, JPG, WEBP or PDF, under 5MB.</div></div>'
    +'<div style="margin-bottom:14px"><label class="label">Project / Remarks (required)</label><textarea class="input" id="invRemarks" rows="2" placeholder="e.g. Office renovation project — bought cement and tiles"></textarea></div>'
    +'<button class="btn btn-p" onclick="submitPurchase()" style="width:100%;justify-content:center">Submit Invoice</button>'
    +'</div>'
    +'<div class="card"><div style="overflow-x:auto"><table>'
    +'<thead><tr><th>Date</th><th>Project / Remarks</th><th>File</th></tr></thead><tbody>'
    +(invs.length===0?'<tr><td colspan="3" style="text-align:center;color:#94a3b8;padding:32px">No purchase invoices uploaded yet</td></tr>':
    invs.map(function(p){
      return '<tr><td>'+fd(p.date)+'</td><td style="max-width:220px;font-size:12px;color:#475569">'+p.remarks+'</td><td><a href="'+p.fileData+'" download="'+p.fileName+'" class="btn btn-o btn-sm">View</a></td></tr>';
    }).join(''))
    +'</tbody></table></div></div></div>';
}
var _pendingInvoiceData=null;
var _pendingInvoiceName=null;
function onInvoiceFileChosen(e){
  var file=e.target.files&&e.target.files[0];
  if(!file)return;
  if(file.size>5*1024*1024){toast('File too large — please use a file under 5MB','err');e.target.value='';return;}
  var reader=new FileReader();
  reader.onload=function(ev){
    _pendingInvoiceData=ev.target.result;
    _pendingInvoiceName=file.name;
    var box=document.getElementById('invPreviewBox');
    if(box){
      if(file.type.indexOf('image')===0){
        box.innerHTML='<img src="'+_pendingInvoiceData+'" style="max-height:64px;max-width:100%">';
      } else {
        box.innerHTML='<span style="color:#0f766e;font-size:12px;font-weight:600">&#128196; '+file.name+'</span>';
      }
    }
  };
  reader.readAsDataURL(file);
}
function submitPurchase(){
  var remarks=document.getElementById('invRemarks').value.trim();
  if(!_pendingInvoiceData){toast('Please select an invoice file','err');return;}
  if(!remarks){toast('Project / remarks is required','err');return;}
  var invs=getPI();
  invs.push({id:nid(invs),userId:CU.id,date:td(),remarks:remarks,fileName:_pendingInvoiceName,fileData:_pendingInvoiceData,createdAt:new Date().toISOString()});
  setPI(invs);
  _pendingInvoiceData=null;_pendingInvoiceName=null;
  var admins=getU().filter(function(u){return u.role==='admin';});
  admins.forEach(function(a){pushNotif(a.id,'New Purchase Invoice',CU.name+' uploaded a purchase invoice: '+remarks,'info');});
  go('/purchase');toast('Invoice submitted!');
}
