function showTab(t){
  document.getElementById('ti').style.display=t==='i'?'':'none';
  document.getElementById('ts').style.display=t==='s'?'':'none';
  document.getElementById('tp1').style.cssText='padding:9px 18px;border:none;background:none;cursor:pointer;font-size:13px;'+(t==='i'?'font-weight:600;color:#0f766e;border-bottom:2px solid #0f766e;margin-bottom:-2px':'color:#64748b;');
  document.getElementById('tp2').style.cssText='padding:9px 18px;border:none;background:none;cursor:pointer;font-size:13px;'+(t==='s'?'font-weight:600;color:#0f766e;border-bottom:2px solid #0f766e;margin-bottom:-2px':'color:#64748b;');
}
function saveProf(){
  var name=document.getElementById('pn').value.trim();var email=document.getElementById('pe').value.trim();var phone=document.getElementById('pp').value.trim();
  if(!name){toast('Name required','err');return;}
  var users=getU();var i=users.findIndex(function(u){return u.id===CU.id;});
  if(i>=0){users[i]=Object.assign({},users[i],{name:name,email:email,phone:phone});CU=Object.assign({},CU,{name:name,email:email,phone:phone});sessionStorage.setItem('hr_sess',JSON.stringify(CU));}
  setU(users);toast('Profile saved');renderSidebar();
}
function changePwd(){
  var cur=document.getElementById('pc').value;var nw=document.getElementById('pnw').value;var cf=document.getElementById('pcf').value;
  var users=getU();var u=users.filter(function(x){return x.id===CU.id;})[0];
  if(!u||u.password!==cur){toast('Current password incorrect','err');return;}
  if(nw.length<6){toast('New password must be 6+ characters','err');return;}
  if(nw!==cf){toast('Passwords do not match','err');return;}
  var i=users.findIndex(function(x){return x.id===CU.id;});
  users[i].password=nw;setU(users);toast('Password updated');
}
function printSlip(){
  var content=document.getElementById('sc').innerHTML;
  var w=window.open('','_blank');
  w.document.write('<html><head><title>Salary Slip</title><style>body{font-family:Arial,sans-serif;margin:32px;color:#111}table{width:100%;border-collapse:collapse}th,td{border:1px solid #ddd;padding:8px 12px;text-align:left}th{background:#f8f8f8}</style></head><body>'+content+'</body></html>');
  w.document.close();w.focus();w.print();w.close();
}

// ============ MODAL / TOAST ============
function openModal(html){document.getElementById('modalBox').innerHTML=html;document.getElementById('modal').style.display='flex';}
function closeModal(){document.getElementById('modal').style.display='none';}
var toastTmr=null;
function toast(msg,type){
  var el=document.getElementById('toast');
  el.textContent=msg;el.className='toast '+(type==='err'?'toast-err':'toast-ok');
  el.style.display='block';
  if(toastTmr)clearTimeout(toastTmr);
  toastTmr=setTimeout(function(){el.style.display='none';},3000);
}


// ============ DAILY ATTENDANCE REMINDER ============
function scheduleDailyNotif(){
  if(!CU||CU.role!=='employee')return;
  // Request notification permission
  if('Notification' in window && Notification.permission==='default'){
    Notification.requestPermission();
  }
  checkAndScheduleNotif();
}
function checkAndScheduleNotif(){
  if(!CU||CU.role!=='employee')return;
  var now=new Date();
  // IST = UTC+5:30
  var istOffset=5.5*60*60*1000;
  var istNow=new Date(now.getTime()+istOffset);
  var istH=istNow.getUTCHours(),istM=istNow.getUTCMinutes();
  // Target: 21:00 IST
  var targetH=21,targetM=0;
  var msUntilTarget;
  if(istH<targetH||(istH===targetH&&istM<targetM)){
    msUntilTarget=((targetH-istH)*60+(targetM-istM))*60000;
  } else {
    // past 9pm, schedule for tomorrow
    var msSinceMidnight=(istH*60+istM)*60000;
    var msInDay=24*60*60*1000;
    msUntilTarget=msInDay-msSinceMidnight+(targetH*60+targetM)*60000;
  }
  setTimeout(function(){
    fireAttendanceReminder();
    // Reschedule every 24h
    setInterval(fireAttendanceReminder,24*60*60*1000);
  },msUntilTarget);
}
function fireAttendanceReminder(){
  if(!CU||CU.role!=='employee')return;
  var today=new Date().toISOString().slice(0,10);
  var already=getA().filter(function(a){return a.userId===CU.id&&a.date===today;}).length>0;
  if(already)return; // already submitted
  // In-app toast
  showReminderBanner();
  // Browser push notification
  if('Notification' in window && Notification.permission==='granted'){
    var n=new Notification(getCompanyName()+' Staff Portal',{
      body:'\u23F0 Don\u2019t forget to submit your attendance for today!',
      icon:'data:image/svg+xml,<svg xmlns=%22http://www.w3.org/2000/svg%22 viewBox=%220 0 100 100%22><rect width=%22100%22 height=%22100%22 rx=%2220%22 fill=%22%2315283D%22/><text y=%22.9em%22 font-size=%2270%22 x=%2212%22>\u231A</text></svg>',
      tag:'att-reminder',
      requireInteraction:true
    });
    n.onclick=function(){window.focus();n.close();go('/att/submit');};
  }
}
function showReminderBanner(){
  var b=document.getElementById('reminderBanner');
  if(!b)return;
  b.style.display='flex';
  setTimeout(function(){b.style.display='none';},12000);
}

